/*
  Design Studio Framework Styles
  - Monochrome, minimalist, grid-based layout
  - Strong typography and generous whitespace
*/

/* -----------------------------
   Design System
----------------------------- */

:root {
    /* Color palette */
    --color-primary-900: #000000; /* deep black */
    --color-primary-800: #111111;

    --color-secondary-50: #F7F6FA; /* light gray/lilac band */
    --color-secondary-100: #EDEDF2;

    --color-accent-500: #2C8EDB; /* blue checkbox / accents */

    --color-neutral-0: #FFFFFF;
    --color-neutral-800: #111111;
    --color-neutral-500: #777777;

    --color-success: #2E7D32;
    --color-error: #C62828;
    --color-warning: #ED6C02;
    --color-info: #1976D2;

    /* Typography */
    --font-heading: 'Space Grotesk', Helvetica, sans-serif;
    --font-body: 'Work Sans', Arial, sans-serif;
    --font-code: 'Source Code Pro', monospace;

    --font-size-h1: 36px;
    --font-size-h2: 28px;
    --font-size-h3: 22px;
    --font-size-body: 14px;
    --font-size-small: 12px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 16px;
    --space-4: 24px;
    --space-5: 32px;
    --space-6: 48px;
    --space-7: 64px;

    --header-height-desktop: 88px;
    --border-radius-soft: 3px;
    --border-radius-card: 4px;

    --max-width-page: 1200px;
}

/* -----------------------------
   Global Resets & Base Styles
----------------------------- */

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-800);
    background-color: var(--color-neutral-0);
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

.container {
    max-width: var(--max-width-page);
    margin: 0 auto;
    padding-left: var(--space-4);
    padding-right: var(--space-4);
}

.site-main {
    padding-top: var(--space-7);
    padding-bottom: var(--space-7);
}

/* -----------------------------
   Header
----------------------------- */

.site-header {
    position: sticky;
    top: 0;
    z-index: 50;
    background-color: var(--color-neutral-0);
    border-bottom: 1px solid #e5e5e5;
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: var(--header-height-desktop);
}

/* Logo: script-like main word with small tagline */

.site-logo {
    display: flex;
    flex-direction: column;
    justify-content: center;
}

.logo-primary {
    font-family: 'Segoe Script', 'Brush Script MT', cursive;
    font-size: 26px;
    line-height: 1;
    color: var(--color-primary-900);
}

.logo-tagline {
    margin-top: 2px;
    font-family: var(--font-body);
    font-size: 10px;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    color: var(--color-neutral-500);
}

/* Primary navigation */

.primary-nav {
    flex: 1;
    display: flex;
    justify-content: center;
}

.primary-nav ul {
    list-style: none;
    display: flex;
    gap: var(--space-4);
    margin: 0;
    padding: 0;
}

.primary-nav a {
    font-family: var(--font-heading);
    font-size: 12px;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    font-weight: var(--font-weight-medium);
    color: var(--color-neutral-800);
    padding: var(--space-1) 0;
    position: relative;
}

.primary-nav a::after {
    content: '';
    position: absolute;
    left: 0;
    bottom: -6px;
    width: 0;
    height: 1px;
    background-color: var(--color-primary-900);
    transition: width 0.2s ease;
}

.primary-nav a:hover::after,
.primary-nav a:focus::after {
    width: 100%;
}

.primary-nav a.is-active::after {
    width: 100%;
}

/* Header utility: Favorites + Cart */

.header-utility {
    display: flex;
    align-items: center;
    gap: var(--space-3);
    font-family: var(--font-heading);
    font-size: 12px;
    letter-spacing: 0.16em;
    text-transform: uppercase;
}

.utility-link {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    color: var(--color-neutral-800);
}

.utility-link-label {
    font-weight: var(--font-weight-medium);
}

.cart-count {
    font-weight: var(--font-weight-regular);
    color: var(--color-neutral-500);
}

.utility-cart::before {
    content: '';
    display: inline-block;
    width: 14px;
    height: 14px;
    border: 1px solid var(--color-neutral-800);
    border-radius: 2px;
    margin-right: 4px;
    position: relative;
}

.utility-cart::after {
    /* simple cart handle */
    content: '';
    position: relative;
    left: -13px;
    top: -7px;
    display: inline-block;
    width: 8px;
    height: 4px;
    border: 1px solid var(--color-neutral-800);
    border-bottom: none;
    border-radius: 2px 2px 0 0;
}

/* -----------------------------
   Footer
----------------------------- */

.site-footer {
    border-top: 1px solid #e5e5e5;
    background-color: var(--color-neutral-0);
}

.footer-inner {
    padding-top: var(--space-6);
    padding-bottom: var(--space-6);
}

.footer-main {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-5);
    justify-content: space-between;
    margin-bottom: var(--space-5);
}

.footer-brand {
    max-width: 280px;
}

.footer-logo {
    font-family: 'Segoe Script', 'Brush Script MT', cursive;
    font-size: 22px;
    color: var(--color-primary-900);
    margin-bottom: var(--space-2);
}

.footer-description {
    font-size: 13px;
    line-height: var(--line-height-relaxed);
    color: var(--color-neutral-500);
    margin: 0;
}

.footer-columns {
    display: grid;
    grid-template-columns: repeat(3, minmax(140px, 1fr));
    gap: var(--space-5);
}

.footer-heading {
    font-family: var(--font-heading);
    font-size: 11px;
    text-transform: uppercase;
    letter-spacing: 0.18em;
    font-weight: var(--font-weight-semibold);
    color: var(--color-neutral-800);
    margin: 0 0 var(--space-3);
}

.footer-links {
    list-style: none;
    margin: 0;
    padding: 0;
}

.footer-links li + li {
    margin-top: var(--space-2);
}

.footer-links a {
    font-size: 13px;
    color: var(--color-neutral-800);
}

.footer-links a:hover,
.footer-links a:focus {
    color: var(--color-primary-900);
    text-decoration: underline;
}

.footer-bottom {
    border-top: 1px solid #e5e5e5;
    padding-top: var(--space-3);
}

.footer-copy {
    margin: 0;
    font-size: var(--font-size-small);
    color: var(--color-neutral-500);
}

/* -----------------------------
   Generic Components (for reuse)
----------------------------- */

/* Notice card similar to empty basket band */

.notice {
    width: 100%;
    background-color: var(--color-secondary-50);
    padding: var(--space-4) var(--space-5);
    display: flex;
    align-items: center;
    gap: var(--space-3);
    font-size: var(--font-size-body);
    color: var(--color-neutral-800);
}

.notice + .notice {
    margin-top: var(--space-3);
}

.notice-icon-box {
    width: 16px;
    height: 16px;
    border: 2px solid var(--color-accent-500);
    border-radius: 2px;
    flex-shrink: 0;
}

.notice--info {
    border-top: 1px solid #e5e5e5;
}

/* Primary full-width CTA (e.g., Return to Shop) */

.btn-primary-bar {
    display: inline-flex;
    align-items: center;
    justify-content: flex-start;
    width: 100%;
    padding: 18px 24px;
    background-color: var(--color-primary-900);
    color: var(--color-neutral-0);
    border: none;
    border-radius: var(--border-radius-card);
    font-family: var(--font-heading);
    font-size: 12px;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    font-weight: var(--font-weight-semibold);
    cursor: pointer;
}

.btn-primary-bar::before {
    content: '\2190'; /* left arrow */
    margin-right: 12px;
    font-size: 16px;
}

.btn-primary-bar:hover,
.btn-primary-bar:focus {
    background-color: var(--color-primary-800);
}

/* Form basics (minimal, thin borders) */

.form-field {
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
    margin-bottom: var(--space-4);
}

.form-field label {
    font-family: var(--font-heading);
    font-size: 11px;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: var(--color-neutral-800);
}

.form-field input,
.form-field textarea,
.form-field select {
    border: 1px solid #d3d3d3;
    border-radius: 0;
    padding: var(--space-2) var(--space-2);
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    outline: none;
}

.form-field input:focus,
.form-field textarea:focus,
.form-field select:focus {
    border-color: var(--color-neutral-800);
}

/* -----------------------------
   Responsive Adjustments
----------------------------- */

@media (max-width: 960px) {
    .header-inner {
        flex-wrap: wrap;
        justify-content: center;
        row-gap: var(--space-3);
        padding-top: var(--space-3);
        padding-bottom: var(--space-3);
        height: auto;
    }

    .site-logo {
        width: 100%;
        align-items: center;
        text-align: center;
    }

    .primary-nav {
        order: 3;
        width: 100%;
    }

    .primary-nav ul {
        justify-content: center;
        flex-wrap: wrap;
        row-gap: var(--space-2);
    }

    .header-utility {
        order: 2;
    }

    .footer-columns {
        grid-template-columns: 1fr 1fr;
    }
}

@media (max-width: 640px) {
    .container {
        padding-left: var(--space-3);
        padding-right: var(--space-3);
    }

    .footer-columns {
        grid-template-columns: 1fr;
    }

    .footer-main {
        gap: var(--space-4);
    }
}
